package Arrays;

public class OutputInputArray {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		int[] arr = {5, -8, 2, 67, 43, -97};
		int n= arr.length;
		System.out.println(arr.length);
		for(int i=0; i<n; i++) {
			System.out.print(arr[i] +" ");
		}
		System.out.println(arr[2]);
	}

}
